ALTER TABLE `Solicitation` ADD COLUMN `workflowSnapshotJson` JSON NULL, ADD COLUMN `approvalSnapshotJson` JSON NULL, ADD COLUMN `notificationSnapshotJson` JSON NULL;
CREATE TABLE `SolicitationWorkflow` (`id` VARCHAR(191) NOT NULL, `name` VARCHAR(191) NOT NULL, `tipoId` VARCHAR(191) NOT NULL, `departmentId` VARCHAR(191) NULL, `active` BOOLEAN NOT NULL DEFAULT true, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `updatedAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `createdById` VARCHAR(191) NULL, `updatedById` VARCHAR(191) NULL, PRIMARY KEY (`id`), INDEX `SolicitationWorkflow_tipoId_departmentId_active_idx`(`tipoId`, `departmentId`, `active`), CONSTRAINT `SolicitationWorkflow_tipoId_fkey` FOREIGN KEY (`tipoId`) REFERENCES `TipoSolicitacao`(`id`) ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT `SolicitationWorkflow_departmentId_fkey` FOREIGN KEY (`departmentId`) REFERENCES `Department`(`id`) ON DELETE SET NULL ON UPDATE CASCADE) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `SolicitationWorkflowStep` (`id` VARCHAR(191) NOT NULL, `workflowId` VARCHAR(191) NOT NULL, `order` INTEGER NOT NULL, `stepKey` VARCHAR(191) NOT NULL, `label` VARCHAR(191) NOT NULL, `kind` VARCHAR(191) NOT NULL, `defaultDepartmentId` VARCHAR(191) NULL, `approverGroupId` VARCHAR(191) NULL, `requiresApproval` BOOLEAN NOT NULL DEFAULT false, `canAssume` BOOLEAN NOT NULL DEFAULT false, `canFinalize` BOOLEAN NOT NULL DEFAULT false, `enabled` BOOLEAN NOT NULL DEFAULT true, `notificationEmailsJson` JSON NULL, `notificationTemplateJson` JSON NULL, `approvalTemplateJson` JSON NULL, `notificationChannelsJson` JSON NULL, `notificationAdminEmailsJson` JSON NULL, `approverUserIdsJson` JSON NULL, `posX` DOUBLE NULL, `posY` DOUBLE NULL, PRIMARY KEY (`id`), UNIQUE INDEX `SolicitationWorkflowStep_workflowId_stepKey_key`(`workflowId`,`stepKey`), INDEX `SolicitationWorkflowStep_workflowId_order_idx`(`workflowId`,`order`), CONSTRAINT `SolicitationWorkflowStep_workflowId_fkey` FOREIGN KEY (`workflowId`) REFERENCES `SolicitationWorkflow`(`id`) ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT `SolicitationWorkflowStep_defaultDepartmentId_fkey` FOREIGN KEY (`defaultDepartmentId`) REFERENCES `Department`(`id`) ON DELETE SET NULL ON UPDATE CASCADE) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `SolicitationWorkflowTransition` (`id` VARCHAR(191) NOT NULL, `workflowId` VARCHAR(191) NOT NULL, `fromStepKey` VARCHAR(191) NOT NULL, `toStepKey` VARCHAR(191) NOT NULL, PRIMARY KEY (`id`), INDEX `SolicitationWorkflowTransition_workflowId_idx`(`workflowId`), CONSTRAINT `SolicitationWorkflowTransition_workflowId_fkey` FOREIGN KEY (`workflowId`) REFERENCES `SolicitationWorkflow`(`id`) ON DELETE CASCADE ON UPDATE CASCADE) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `SolicitationWorkflowAuditLog` (`id` VARCHAR(191) NOT NULL, `workflowId` VARCHAR(191) NOT NULL, `actorId` VARCHAR(191) NULL, `action` VARCHAR(191) NOT NULL, `beforeJson` JSON NULL, `afterJson` JSON NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `ip` VARCHAR(191) NULL, `userAgent` TEXT NULL, PRIMARY KEY (`id`), INDEX `SolicitationWorkflowAuditLog_workflowId_createdAt_idx`(`workflowId`,`createdAt`), CONSTRAINT `SolicitationWorkflowAuditLog_workflowId_fkey` FOREIGN KEY (`workflowId`) REFERENCES `SolicitationWorkflow`(`id`) ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT `SolicitationWorkflowAuditLog_actorId_fkey` FOREIGN KEY (`actorId`) REFERENCES `User`(`id`) ON DELETE SET NULL ON UPDATE CASCADE) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `SolicitationNotificationLog` (`id` VARCHAR(191) NOT NULL, `solicitationId` VARCHAR(191) NULL, `workflowId` VARCHAR(191) NULL, `stepKey` VARCHAR(191) NULL, `event` VARCHAR(191) NOT NULL, `recipientEmail` VARCHAR(191) NOT NULL, `recipientUserId` VARCHAR(191) NULL, `recipientSource` VARCHAR(191) NULL, `subject` VARCHAR(191) NOT NULL, `bodyPreview` TEXT NULL, `status` VARCHAR(191) NOT NULL, `provider` VARCHAR(191) NULL, `error` TEXT NULL, `sentAt` DATETIME(3) NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), PRIMARY KEY (`id`), INDEX `SolicitationNotificationLog_solicitationId_event_idx`(`solicitationId`,`event`), INDEX `SolicitationNotificationLog_workflowId_stepKey_idx`(`workflowId`,`stepKey`), INDEX `SolicitationNotificationLog_status_createdAt_idx`(`status`,`createdAt`), CONSTRAINT `SolicitationNotificationLog_solicitationId_fkey` FOREIGN KEY (`solicitationId`) REFERENCES `Solicitation`(`id`) ON DELETE SET NULL ON UPDATE CASCADE, CONSTRAINT `SolicitationNotificationLog_workflowId_fkey` FOREIGN KEY (`workflowId`) REFERENCES `SolicitationWorkflow`(`id`) ON DELETE SET NULL ON UPDATE CASCADE, CONSTRAINT `SolicitationNotificationLog_recipientUserId_fkey` FOREIGN KEY (`recipientUserId`) REFERENCES `User`(`id`) ON DELETE SET NULL ON UPDATE CASCADE) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `AuditLog` (`id` VARCHAR(191) NOT NULL, `actorId` VARCHAR(191) NULL, `entityType` VARCHAR(191) NOT NULL, `entityId` VARCHAR(191) NULL, `action` VARCHAR(191) NOT NULL, `beforeJson` JSON NULL, `afterJson` JSON NULL, `metadataJson` JSON NULL, `ip` VARCHAR(191) NULL, `userAgent` TEXT NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), PRIMARY KEY (`id`), INDEX `AuditLog_entityType_entityId_createdAt_idx`(`entityType`,`entityId`,`createdAt`), INDEX `AuditLog_actorId_createdAt_idx`(`actorId`,`createdAt`), CONSTRAINT `AuditLog_actorId_fkey` FOREIGN KEY (`actorId`) REFERENCES `User`(`id`) ON DELETE SET NULL ON UPDATE CASCADE) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `PermissionAuditLog` (`id` VARCHAR(191) NOT NULL, `actorId` VARCHAR(191) NULL, `targetUserId` VARCHAR(191) NULL, `action` VARCHAR(191) NOT NULL, `beforeJson` JSON NULL, `afterJson` JSON NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `ip` VARCHAR(191) NULL, `userAgent` TEXT NULL, PRIMARY KEY (`id`), INDEX `PermissionAuditLog_targetUserId_createdAt_idx`(`targetUserId`,`createdAt`), CONSTRAINT `PermissionAuditLog_actorId_fkey` FOREIGN KEY (`actorId`) REFERENCES `User`(`id`) ON DELETE SET NULL ON UPDATE CASCADE, CONSTRAINT `PermissionAuditLog_targetUserId_fkey` FOREIGN KEY (`targetUserId`) REFERENCES `User`(`id`) ON DELETE SET NULL ON UPDATE CASCADE) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `TipoSolicitacaoAuditLog` (`id` VARCHAR(191) NOT NULL, `tipoId` VARCHAR(191) NOT NULL, `actorId` VARCHAR(191) NULL, `action` VARCHAR(191) NOT NULL, `beforeJson` JSON NULL, `afterJson` JSON NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `ip` VARCHAR(191) NULL, `userAgent` TEXT NULL, PRIMARY KEY (`id`), INDEX `TipoSolicitacaoAuditLog_tipoId_createdAt_idx`(`tipoId`,`createdAt`), CONSTRAINT `TipoSolicitacaoAuditLog_tipoId_fkey` FOREIGN KEY (`tipoId`) REFERENCES `TipoSolicitacao`(`id`) ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT `TipoSolicitacaoAuditLog_actorId_fkey` FOREIGN KEY (`actorId`) REFERENCES `User`(`id`) ON DELETE SET NULL ON UPDATE CASCADE) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
